INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('招聘专员 - 成都（校招）', '金融', '成都', '上市公司', 6000, 12000, '1. 熟练掌握招聘全流程操作规范，可独立完成从需求收集到 offer 发放的全闭环工作；2. 具备招聘渠道规划、拓展与维护能力，可根据岗位需求匹配最优招聘渠道；3. 具备简历筛选、多轮面试组织与评估能力，可独立完成候选人全流程跟进；4. 具备人才储备库搭建与维护能力，可针对核心岗位建立人才池；5. 可独立完成招聘面试题库的搭建与维护，具备基础的招聘制度体系搭建能力。', '1. 具备优秀的沟通协调能力，可高效对接业务部门与候选人；2. 工作严谨细致，有极强的责任心和执行力，可高效完成多线程工作；3. 具备较强的规划能力和问题解决能力，可主动优化招聘流程与渠道；4. 学习能力强，可快速理解金融行业的岗位需求与合规要求。', 1, '友好', '1. 汇总各部门的年度人员需求计划并进行审核，根据汇总计划制定公司年度人力计划；2. 根据部门招聘需求，储备招聘渠道，选择最有效的招聘渠道；3. 根据招聘需求，在选定的招聘渠道上发布招聘信息；4. 根据渠道反馈的应聘信息，汇总并进行应聘资料的初步筛选，形成初试名单；5. 按照初试名单，组织初试，对应聘人员进行第二次筛选；6. 根据初试结果名单，组织相关部门人员参与复试过程，对应聘者进行第三次筛选；7. 根据公司总体用人需求，针对核心管理和专业人员，建立人才储备库；8. 负责对招聘渠道实施规划、维护和拓展工作，保障招聘工作的有效性；9. 建立和维护各级各类人员的招聘面试题库。', '招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 招聘数据分析, 招聘制度与体系搭建', '大专及以上', '专业不限，人力资源管理相关专业优先', '接受应届毕业生 / 毕业 1 年内人群，有金融行业招聘相关经验优先', '应届生校招', '人力资源管理师相关证书优先、有金融行业招聘经验优先、有校园招聘项目运营经验优先', '6k-12k / 月', '45801', NULL, 'https://www.shixiseng.com/intern/inn_lz4bammiocul?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('HR Intern - Corp HRBP（人力资源实习生 - 企业 HRBP 方向）-上海', '快消', '上海', '外资企业', 120, 180, '1. 英语口语及书面表达流利 2. 熟练使用 Microsoft Office 办公软件（Excel、Word、PPT 等） 3. 具备基础的招聘流程执行、人事档案整理能力', '1. 强烈的责任心与执行力 2. 优秀的沟通表达与跨部门协作能力 3. 注重细节，具备良好的团队合作精神 4. 能灵活应对临时工作与多任务处理', 1, '极度友好', '1. 负责办公室实习生招聘全流程执行，包含简历筛选、电话面试及面试安排 2. 支持实习生入职与离职流程办理，整理人事档案（P-file），并处理考勤管理相关工作 3. 完成临时 HR 工作：包括 HR 文档归档、内部销售物料分发、跨部门沟通协作等', '招聘全流程执行, 简历筛选与面试, 员工关系支持', '本科及以上', '人力资源管理、工商管理等管理类相关专业优先，无强制专业限制', '在校大学生，可稳定实习 6 个月，每周到岗 4 天，有人力资源相关实习经验优先', '日常实习', '1. 有快消 / 时尚行业 HR 相关实习经验 2. 持有英语四六级 / 专四专八证书 3. 有招聘或员工关系相关项目经验', '150 元 / 天', '46079', '46260', 'https://www.shixiseng.com/intern/inn_vlqla0wckjju?pcm=pc_SearchList', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HR Summer Intern（人力资源暑期实习生）-上海', '其他', '上海', '外资企业', 150, 250, '1. 熟练使用 Microsoft Office 办公软件（Word、Excel、PPT 等） 2. 具备良好的英语读写及沟通能力 3. 具备基础的项目参与与执行能力', '1. 强烈的责任心与主动学习意愿 2. 优秀的沟通表达与跨团队协作能力 3. 细节导向，能高效处理多任务 4. 具备较强的适应性与抗压能力', 1, '极度友好', '1. 在资深员工或 HR 经理的指导与带教下，参与并助力各类 HR 职能模块（人才发展、HR 咨询、HR 传播等）的项目推进 2. 处理 HR 团队内不同小组的日常事务性工作 3. 按需参与专项重点项目 4. 支持临时交办的各项工作任务 5. 实习期间围绕工作任务落地若干项目以产出具体成果，表现优异者可获得全职 HR 管培生录用机会', 'OD 组织发展支持, 员工关系支持', '本科及以上', '人力资源管理、工商管理、心理学等管理类 / 社科类相关专业优先，无强制专业限制', '在校大学生，暑期实习，可稳定实习 6 个月，每周到岗 4 天，有人力资源相关实习经验优先', '暑期实习', '1. 毕业于海内外知名院校，拥有优异学业成绩 2. 有 HR 相关实习或项目经验 3. 持有英语四六级 / 托福雅思等语言证书 4. 具备项目管理或校园活动组织经验', '150-250 元 / 天', '46091', NULL, 'https://www.shixiseng.com/intern/inn_eway0opehqtd?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('组织发展专员（OD 方向）-上海', '文化传媒 / 广告', '上海', '外资企业', 96, 144, '1. 具备数据分析能力，能熟练使用 Excel 进行数据整理与分析 2. 熟练使用 Office 办公软件（Word、PPT 等） 3. 具备基础的项目文案撰写与汇报能力', '1. 工作态度认真负责，细致耐心，具备较强的责任心 2. 具备优秀的执行力、逻辑思考能力与沟通表达能力 3. 具备良好的团队合作精神，能融入团队并发挥价值', 1, '极度友好', '1. 参与 HR 部门各项项目的 Brainstorming（头脑风暴），拓展视野与格局 2. 参与整合营销、传播咨询、人才培养、外资集团客户资源维护等项目的执行 3. 负责 HR 相关项目的落地与推进，参与项目全流程管理', '招聘全流程执行, 校招项目运营, OD 组织发展支持', '本科及以上', '不限，人力资源管理、工商管理、心理学、社会学等相关专业优先', '在校大学生（大一至大四），可实习 3 个月，每周至少到岗 5 天，有相关实习经验优先', '日常实习', '1. 有 4A 广告公司 / 五百强企业实习经历 2. 有组织发展、人才发展、员工关系相关项目经验 3. 具备良好的英语听说读写能力', '120 元 / 天', '46136', '46136', 'https://www.shixiseng.com/intern/inn_sfrtrpcm1fah?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('人力资源实习生-上海（实习）', '金融', '上海', '民营企业', 160, 240, '1. 熟练使用 Office 办公软件（Word、Excel、PPT），具备基础的数据整理能力； 2. 具备基础的招聘流程执行、文档归档与数据录入能力； 3. 具备基础的活动策划与执行协助能力。', '1. 工作认真负责，仔细耐心，注重细节； 2. 具备优秀的执行力、逻辑思考能力与沟通表达能力； 3. 具备良好的团队合作精神，多任务处理能力强。', 1, '极度友好', '1. 协助招聘专员完成简历筛选、面试邀约（电话 / 微信）、面试现场接待与记录工作，整理招聘数据，更新招聘台账，推进候选人面试进度； 2. 员工关系：协助整理员工档案，办理入职离职相关手续（资料收集、系统录入），参与员工关怀活动的筹备与执行； 3. 培训支持：配合培训项目完成培训通知下发、培训物料准备与签到、整理培训签到、签到表及培训总结； 4. 行政及文档管理：负责人力资源部日常物资申请与管理、整理部门文件资料与系统基础数据的录入与维护，确保资料规范、准确； 5. 协助完成部门及临时的其他临时性工作（如员工活动策划、制度文件整理等），配合各模块专员推进人力资源相关工作落地。', '招聘全流程执行, 简历筛选与面试, 员工关系支持', '本科及以上', '人力资源管理、工商管理、劳动与社会保障等相关专业优先，无强制限制', '在校大学生（大一 / 大二可接受），可实习 3 个月，每周到岗 3 天，有相关实习经验优先', '日常实习', '1. 有校园 / 企业活动组织经验； 2. 有人力资源相关实习经历； 3. 熟练掌握 Excel 函数（如 XLOOKUP、VLOOKUP）加分。', '200 元 / 天', '46085', '46201', 'https://www.shixiseng.com/intern/inn_wlr2kqvvonxj?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）');